import React, { useState } from "react";
import { authAPI } from "../services/api";
import { useAuth } from "../context/AuthContext";
import Navbar from "../components/Navbar";

const SKILLS_ALL = ["JavaScript","Python","React","Node.js","TypeScript","MongoDB","SQL","Docker","AWS","Machine Learning","TensorFlow","Git","DSA","System Design","CSS","Express","PostgreSQL","Linux","Redis","Kubernetes","Flutter","React Native","Figma","Django","FastAPI"];

export default function Profile() {
  const { user, updateUser, theme, toggleTheme } = useAuth();
  const fileRef = useRef();
  const [editing, setEditing] = useState(false);
  const [form, setForm] = useState({ name:user?.name||"", bio:user?.bio||"", college:user?.college||"", year:user?.year||"", linkedin:user?.linkedin||"", github:user?.github||"", targetRole:user?.targetRole||"" });
  const [saving, setSaving] = useState(false);
  const [activeTab, setActiveTab] = useState("overview");
  const [updatingSkill, setUpdatingSkill] = useState(null);

  const handleAvatarUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    if (file.size > 2 * 1024 * 1024) { alert('Max 2MB'); return; }
    const reader = new FileReader();
    reader.onload = async () => {
      try {
        const r = await uploadAvatar(reader.result);
        updateUser(r.data.user);
      } catch { alert('Upload failed'); }
    };
    reader.readAsDataURL(file);
  };

  const save = async () => {
    setSaving(true);
    try {
      const r = await authAPI.updateProfile(form);
      updateUser(r.data.user);
      setEditing(false);
    } catch {}
    finally { setSaving(false); }
  };

  const updateProgress = async (skill, status, progress) => {
    setUpdatingSkill(skill);
    try {
      const r = await authAPI.updateProgress({ skill, status, progress });
      updateUser({ ...user, skillProgress: r.data.skillProgress, points: r.data.points, level: r.data.level });
    } catch {}
    finally { setUpdatingSkill(null); }
  };

  const getProgress = (skill) => user?.skillProgress?.find(s => s.skill === skill);
  const LEVEL_C = { Expert:"var(--amber)", Advanced:"var(--blue)", Intermediate:"var(--green)", Beginner:"var(--muted)" };
  const STATUS_C = { completed:"var(--green)", learning:"var(--blue)", planning:"var(--muted)" };

  // Naive resume template
  const generateResume = () => {
    const skills = user?.skills?.join(", ") || "Not specified";
    const certs = user?.certificates?.map(c => `• ${c.title} (${c.skill})`).join("\n") || "None yet";
    const content = `${user?.name?.toUpperCase() || "YOUR NAME"}
${user?.college || "Your College"} | ${user?.linkedin ? "LinkedIn: " + user.linkedin : ""} | ${user?.github ? "GitHub: " + user.github : ""}

OBJECTIVE
${user?.bio || "Passionate CS student seeking opportunities in " + (user?.targetRole || "software engineering") + "."}

TECHNICAL SKILLS
${skills}

CERTIFICATIONS
${certs}

EDUCATION
${user?.college || "Your College"}
B.Tech Computer Science / Your Branch
Year: ${user?.year || "Final Year"}

TARGET ROLE: ${user?.targetRole || "Software Engineer"}
Points Earned: ${user?.points || 0} | Level: ${user?.level || "Beginner"}
`;
    const blob = new Blob([content], { type: "text/plain" });
    const a = document.createElement("a");
    a.href = URL.createObjectURL(blob);
    a.download = `${user?.name?.replace(/ /g,"_")}_Resume_Draft.txt`;
    a.click();
  };

  return (
    <div style={{ minHeight:"100vh", background:"var(--bg)", color:"var(--text)" }}>
      <Navbar/>
      <div style={{ maxWidth:900, margin:"0 auto", padding:"2rem 1.5rem" }}>

        {/* Profile header */}
        <div className="sg-card" style={{ marginBottom:"1.5rem", borderColor:"rgba(61,142,240,.3)" }}>
          <div style={{ display:"flex", justifyContent:"space-between", flexWrap:"wrap", gap:"1.5rem" }}>
            <div style={{ display:"flex", gap:"1.2rem", alignItems:"center" }}>
              <div style={{ position:"relative",display:"inline-block" }}>
                {user?.avatar ? (
                  <img src={user.avatar} alt="avatar" style={{ width:70,height:70,borderRadius:"50%",objectFit:"cover",border:"3px solid var(--blue)" }}/>
                ) : (
                  <div className="sg-avatar" style={{ width:70, height:70, fontSize:"1.8rem" }}>{user?.name?.[0]}</div>
                )}
                <button onClick={() => fileRef.current?.click()} title="Upload photo" style={{ position:"absolute",bottom:0,right:0,width:24,height:24,borderRadius:"50%",background:"var(--blue)",border:"none",cursor:"pointer",fontSize:".75rem",display:"flex",alignItems:"center",justifyContent:"center",color:"#fff" }}>📷</button>
                <input ref={fileRef} type="file" accept="image/*" style={{ display:"none" }} onChange={handleAvatarUpload} />
              </div>
              <div>
                {editing ? (
                  <input value={form.name} onChange={e=>setForm({...form,name:e.target.value})} className="sg-input" style={{ marginBottom:".4rem", fontWeight:700 }} placeholder="Full Name"/>
                ) : (
                  <h2 style={{ fontFamily:"'Syne',sans-serif", fontWeight:800, fontSize:"1.4rem", marginBottom:".2rem" }}>{user?.name}</h2>
                )}
                <p style={{ color:"var(--blue)", fontSize:".88rem", marginBottom:".2rem" }}>{user?.college || "Add your college"}</p>
                <div style={{ display:"flex", gap:".5rem", flexWrap:"wrap" }}>
                  <span style={{ color:LEVEL_C[user?.level]||"var(--muted)", fontWeight:600, fontSize:".8rem" }}>✦ {user?.level}</span>
                  <span style={{ color:"var(--muted)", fontSize:".8rem" }}>· {user?.authProvider === "google" ? "🔵 Google" : user?.authProvider === "linkedin" ? "🔗 LinkedIn" : "📧 Email"}</span>
                </div>
              </div>
            </div>
            <div style={{ display:"flex", gap:".6rem", flexWrap:"wrap", alignItems:"flex-start" }}>
              {editing ? (
                <><button onClick={save} disabled={saving} className="sg-btn sg-btn-primary">{saving?"Saving...":"Save"}</button>
                <button onClick={()=>setEditing(false)} className="sg-btn sg-btn-outline">Cancel</button></>
              ) : (
                <><button onClick={()=>setEditing(true)} className="sg-btn sg-btn-outline">✏️ Edit</button>
                <button onClick={generateResume} className="sg-btn sg-btn-green">📄 Export Resume</button></>
              )}
            </div>
          </div>

          {/* Stats */}
          <div style={{ display:"flex", gap:"1.5rem", flexWrap:"wrap", marginTop:"1.2rem", padding:"1rem", background:"var(--bg)", borderRadius:10, border:"1px solid var(--border)" }}>
            {[
              { l:"Points",   v:user?.points||0,                   c:"var(--amber)" },
              { l:"Skills",   v:user?.skills?.length||0,           c:"var(--blue)" },
              { l:"Streak",   v:`${user?.streak||0}d`,             c:"var(--red)" },
              { l:"Analyses", v:user?.analysisCount||0,            c:"var(--purple)" },
              { l:"Certs",    v:user?.certificates?.length||0,     c:"var(--green)" },
            ].map(s => (
              <div key={s.l} style={{ textAlign:"center" }}>
                <div style={{ fontFamily:"'Syne',sans-serif", fontSize:"1.5rem", fontWeight:900, color:s.c }}>{s.v}</div>
                <div style={{ color:"var(--muted)", fontSize:".72rem" }}>{s.l}</div>
              </div>
            ))}
          </div>
        </div>

        {/* Tabs */}
        <div style={{ display:"flex", gap:".4rem", marginBottom:"1.2rem", background:"var(--bg2)", borderRadius:10, padding:4, border:"1px solid var(--border)" }}>
          {[["overview","👤 Overview"],["progress","📈 Skill Progress"],["certs","📜 Certificates"],["badges","🎖 Badges"]].map(([t,l])=>(
            <button key={t} onClick={()=>setActiveTab(t)} style={{ flex:1, padding:".5rem", borderRadius:8, border:"none", cursor:"pointer", fontFamily:"inherit", fontWeight:600, fontSize:".84rem", transition:"all .2s",
              background: activeTab===t?"linear-gradient(135deg,var(--blue),var(--purple))":"transparent",
              color: activeTab===t?"#fff":"var(--muted)" }}>{l}</button>
          ))}
        </div>

        {/* Overview */}
        {activeTab === "overview" && (
          <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:"1rem" }}>
            <div className="sg-card">
              <h4 style={{ fontWeight:700, marginBottom:"1rem" }}>Personal Info</h4>
              {editing ? (
                <div style={{ display:"grid", gap:".7rem" }}>
                  {[["bio","Bio","Student passionate about tech...","textarea"],["college","College","IIT Bombay"],["year","Year","3rd Year / Final Year"],["targetRole","Target Role","Full Stack Developer"],["linkedin","LinkedIn URL","https://linkedin.com/in/..."],["github","GitHub URL","https://github.com/..."]].map(([k,l,ph,type])=>(
                    <div key={k}>
                      <label className="sg-label">{l}</label>
                      {type==="textarea"
                        ? <textarea value={form[k]} onChange={e=>setForm({...form,[k]:e.target.value})} placeholder={ph} className="sg-input" style={{ height:70, resize:"none" }}/>
                        : <input value={form[k]} onChange={e=>setForm({...form,[k]:e.target.value})} placeholder={ph} className="sg-input"/>
                      }
                    </div>
                  ))}
                </div>
              ) : (
                <div style={{ display:"grid", gap:".6rem" }}>
                  {[["🎓 College",user?.college],["📅 Year",user?.year],["🎯 Target",user?.targetRole],["🔗 LinkedIn",user?.linkedin],["💻 GitHub",user?.github]].map(([l,v])=>(
                    v ? <div key={l} style={{ fontSize:".85rem" }}><span style={{ color:"var(--muted)" }}>{l}: </span><span>{v}</span></div> : null
                  ))}
                  {user?.bio && <p style={{ color:"var(--muted)", fontSize:".85rem", lineHeight:1.6, borderTop:"1px solid var(--border)", paddingTop:".6rem" }}>{user.bio}</p>}
                  {!user?.college && !user?.bio && <p style={{ color:"var(--muted)", fontSize:".85rem" }}>Click Edit to add your details.</p>}
                </div>
              )}
            </div>
            <div className="sg-card">
              <h4 style={{ fontWeight:700, marginBottom:"1rem" }}>🛠 My Skills ({user?.skills?.length||0})</h4>
              <div style={{ display:"flex", flexWrap:"wrap", gap:".35rem", marginBottom:"1rem" }}>
                {user?.skills?.length ? user.skills.map(s=><span key={s} className="sg-tag sg-tag-blue">{s}</span>)
                  : <p style={{ color:"var(--muted)", fontSize:".85rem" }}>No skills yet. Run an analysis!</p>}
              </div>
              <div style={{ background:"var(--bg)", border:"1px solid var(--border)", borderRadius:8, padding:".6rem .8rem" }}>
                <p style={{ color:"var(--muted)", fontSize:".75rem" }}>Skills are updated automatically when you run an analysis or upload your resume.</p>
              </div>
            </div>
          </div>
        )}

        {/* Progress Tab */}
        {activeTab === "progress" && (
          <div className="sg-card">
            <h4 style={{ fontWeight:700, marginBottom:"1rem" }}>📈 Skill Progress Tracker</h4>
            <p style={{ color:"var(--muted)", fontSize:".85rem", marginBottom:"1rem" }}>Track your learning journey. Update skill status to earn points (50pts per completed skill).</p>
            {SKILLS_ALL.slice(0,16).map(skill => {
              const prog = getProgress(skill);
              return (
                <div key={skill} style={{ display:"flex", alignItems:"center", gap:".8rem", padding:".6rem 0", borderBottom:"1px solid var(--border)" }}>
                  <span style={{ minWidth:130, fontWeight:600, fontSize:".85rem" }}>{skill}</span>
                  <div className="sg-progress" style={{ flex:1 }}>
                    <div className="sg-bar" style={{ width:`${prog?.progress||0}%` }}/>
                  </div>
                  <span style={{ minWidth:36, fontSize:".78rem", color:"var(--muted)" }}>{prog?.progress||0}%</span>
                  <select value={prog?.status||"planning"} onChange={e=>updateProgress(skill,e.target.value,e.target.value==="completed"?100:prog?.progress||0)}
                    disabled={updatingSkill===skill}
                    style={{ background:"var(--bg3)", border:"1px solid var(--border)", borderRadius:8, padding:".3rem .5rem", color:STATUS_C[prog?.status||"planning"]||"var(--muted)", fontSize:".76rem", cursor:"pointer" }}>
                    <option value="planning">Planning</option>
                    <option value="learning">Learning</option>
                    <option value="completed">Done ✓</option>
                  </select>
                </div>
              );
            })}
          </div>
        )}

        {/* Certs Tab */}
        {activeTab === "certs" && (
          <div className="sg-card">
            <h4 style={{ fontWeight:700, marginBottom:"1rem" }}>📜 Certificates ({user?.certificates?.length||0})</h4>
            {!user?.certificates?.length ? (
              <div style={{ textAlign:"center", padding:"2rem", color:"var(--muted)" }}>
                <div style={{ fontSize:"2.5rem", marginBottom:".5rem" }}>📭</div>
                <p>No certificates yet. Upload them in the Certificates section!</p>
              </div>
            ) : (
              <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(220px,1fr))", gap:".8rem" }}>
                {user.certificates.map((c,i)=>(
                  <div key={i} style={{ background:"var(--bg)", border:"1px solid var(--border)", borderRadius:10, padding:"1rem" }}>
                    <div style={{ fontSize:"1.5rem", marginBottom:".4rem" }}>📜</div>
                    <p style={{ fontWeight:700, fontSize:".88rem" }}>{c.title}</p>
                    <p style={{ color:"var(--blue)", fontSize:".8rem" }}>{c.skill}</p>
                    <p style={{ color:"var(--amber)", fontSize:".76rem" }}>+{c.points}pts</p>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        {/* Badges Tab */}
        {activeTab === "badges" && (
          <div className="sg-card">
            <h4 style={{ fontWeight:700, marginBottom:"1rem" }}>🎖 Badges ({user?.badges?.length||0})</h4>
            {!user?.badges?.length ? (
              <div style={{ textAlign:"center", padding:"2rem", color:"var(--muted)" }}>
                <div style={{ fontSize:"2.5rem", marginBottom:".5rem" }}>🎖</div>
                <p>No badges yet. Complete challenges to earn your first badge!</p>
              </div>
            ) : (
              <div style={{ display:"flex", flexWrap:"wrap", gap:"1rem" }}>
                {user.badges.map((b,i)=>(
                  <div key={i} style={{ textAlign:"center", background:"var(--bg)", border:"1px solid var(--amber)", borderRadius:12, padding:"1rem 1.5rem" }}>
                    <div style={{ fontSize:"2rem" }}>🏆</div>
                    <p style={{ fontWeight:600, fontSize:".82rem", marginTop:".3rem" }}>{b.badgeId}</p>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}
